import React from 'react';

const Notifications: React.FC = () => {
  return (
    <div className="space-y-6">
      <h2 className="text-2xl font-bold tracking-tight">Notifications</h2>

      <div className="space-y-4">
        <div className="rounded-md border bg-blue-50 dark:bg-blue-900/20 p-4">
          <p className="text-sm font-medium text-blue-800 dark:text-blue-300">Welcome to SOC Alert Platform!</p>
          <span className="text-xs text-blue-600 dark:text-blue-400">Just now</span>
        </div>
        <div className="rounded-md border bg-card p-4">
          <p className="text-sm font-medium">Weekly AI Summary is ready to review.</p>
          <span className="text-xs text-gray-500">2 days ago</span>
        </div>
      </div>
    </div>
  );
};

export default Notifications;
